        for item in data:
            if item > 0:
                result.append(item * 2)
    elif mode == 'square':
        for item in data:
            if item > 0:
                result.append(item ** 2)
    elif mode == 'half':
        for item in data:
            if item > 0:
                result.append(item / 2)
    return result

